            saxReader.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true);
            // Disable external general entities to prevent XXE attacks
            saxReader.setFeature("http://xml.org/sax/features/external-general-entities", false);
            // Disable external parameter entities to prevent XXE attacks
            saxReader.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            // Disable loading of external DTDs to prevent XXE and unwanted external resource access
            saxReader.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        } catch (SAXException e) {
            throw new Exception("Failed to configure XML parser security settings", e);
        }
        org.dom4j.Document dom4jDoc;
        // Read XML file using try-with-resources to ensure input stream is closed properly
        try (FileInputStream fis = new FileInputStream(new File(trimmedPath))) {
            dom4jDoc = saxReader.read(fis);
        } catch (IOException e) {
            throw new Exception("Error reading configuration file: " + e.getMessage(), e);
        } catch (org.dom4j.DocumentException e) {
            throw new Exception("Invalid XML format in configuration file: " + e.getMessage(), e);
        }
        // Convert dom4j Document to W3C DOM Document
        DOMWriter domWriter = new DOMWriter();
        try {
            return domWriter.write(dom4jDoc);
        } catch (org.dom4j.DocumentException e) {
            throw new Exception("Failed to convert XML document to W3C DOM format: " + e.getMessage(), e);
        }
    }
}
